  1	import React, { FC, useEffect, useMemo, useState } from 'react';
  2	import { NavLink, Route, Routes, useLocation, useParams } from 'react-router-dom-v5-compat';
  3	import classNames from 'classnames';
  4	import { VirtualMachineModel } from 'src/views/dashboard-extensions/utils';
  5	
  6	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  7	import { isEmpty } from '@kubevirt-utils/utils/utils';
  8	import { Nav, NavList } from '@patternfly/react-core';
  9	
 10	import StateHandler from '../StateHandler/StateHandler';
 11	
 12	import useDynamicPages from './utils/useDynamicPages';
 13	import { NavPageKubevirt, trimLastHistoryPath } from './utils/utils';
 14	
 15	import './horizontal-nav-bar.scss';
 16	
 17	type HorizontalNavbarProps = {
 18	  error?: any;
 19	  instanceTypeExpandedSpec?: V1VirtualMachine;
 20	  loaded: boolean;
 21	  pages: NavPageKubevirt[];
 22	  vm?: V1VirtualMachine;
 23	};
 24	
 25	const HorizontalNavbar: FC<HorizontalNavbarProps> = ({
 26	  error,
 27	  instanceTypeExpandedSpec,
 28	  loaded,
 29	  pages,
 30	  vm,
 31	}) => {
 32	  const location = useLocation();
 33	
 34	  const params = useParams();
 35	
 36	  const dynamicPluginPages = useDynamicPages(VirtualMachineModel);
 37	
 38	  const allPages = useMemo(
 39	    () => [...pages, ...(dynamicPluginPages || [])] as NavPageKubevirt[],
 40	    [pages, dynamicPluginPages],
 41	  );
 42	
 43	  const paths = allPages.map((page) => page.href);
 44	
 45	  useEffect(() => {
 46	    const defaultPage = allPages.find(({ href }) => isEmpty(href));
 47	
 48	    const initialActiveTab =
 49	      allPages.find(({ href }) => !isEmpty(href) && location?.pathname.includes('/' + href)) ||
 50	      defaultPage;
 51	
 52	    setActiveItem(initialActiveTab?.name?.toLowerCase());
 53	  }, [allPages, location?.pathname]);
 54	
 55	  const [activeItem, setActiveItem] = useState<number | string>();
 56	  return (
 57	    <>
 58	      <Nav variant="horizontal">
 59	        <NavList className="co-m-horizontal-nav__menu horizontal-nav-bar__list">
 60	          {allPages.map((item) => {
 61	            if (item?.isHidden) return null;
 62	
 63	            return (
 64	              <NavLink
 65	                className={classNames('horizontal-nav-bar__menu-item', {
 66	                  active: activeItem === item.name.toLowerCase(),
 67	                })}
 68	                data-test-id={`horizontal-link-${item.name}`}
 69	                id={`horizontal-pageHeader-${item.name}`}
 70	                key={item.name}
 71	                onClick={() => setActiveItem(item.name.toLowerCase())}
 72	                to={trimLastHistoryPath(location, paths) + item.href}
 73	              >
 74	                {item.name}
 75	              </NavLink>
 76	            );
 77	          })}
 78	        </NavList>
 79	      </Nav>
 80	      <Routes>
 81	        {allPages.map((page) => {
 82	          const Component = page.component;
 83	          return (
 84	            <Route
 85	              Component={(props) => (
 86	                <StateHandler error={error} loaded={loaded} withBullseye>
 87	                  <Component
 88	                    instanceTypeExpandedSpec={instanceTypeExpandedSpec}
 89	                    obj={vm}
 90	                    params={params}
 91	                    {...props}
 92	                  />
 93	                </StateHandler>
 94	              )}
 95	              key={page.href}
 96	              path={page.href}
 97	            />
 98	          );
 99	        })}
100	      </Routes>
101	    </>
102	  );
103	};
104	
105	export default HorizontalNavbar;

